61	func investigationRetryInitialMinPower(b *bead.Bead, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, agent.ExecuteBeadReport, bool) {
62		// Numeric hint: written by the no-changes smart-retry path one step at a time.
63		if floor, ok := numericTierFloorHint(b); ok {
64			if baseMinPower > floor {
65				return baseMinPower, smartRouteUnavailableReport(b, baseMinPower, maxPower, nil), true
66			}
67			if maxPower > 0 && floor >= maxPower {
68				return baseMinPower, smartRouteUnavailableReport(b, floor, maxPower, nil), true
69			}
70			return floor, agent.ExecuteBeadReport{}, false
71		}
72		// Tier-name hint: written by the review-triage path; jump to highest viable.
73		if tier, ok := triageTierHint(b); !ok || tier != policyescalation.TierSmart {
74			return baseMinPower, agent.ExecuteBeadReport{}, false
75		}
76		floor, err := highestViableEscalationFloor(ladder)
77		if err != nil {
78			return baseMinPower, smartRouteUnavailableReport(b, baseMinPower, maxPower, err), true
79		}
80		if baseMinPower > floor {
81			return baseMinPower, smartRouteUnavailableReport(b, baseMinPower, maxPower, nil), true
82		}
83		if maxPower > 0 && floor >= maxPower {
84			return baseMinPower, smartRouteUnavailableReport(b, floor, maxPower, nil), true
85		}
86		return floor, agent.ExecuteBeadReport{}, false
87	}
88	
89	// numericTierFloorHint returns the numeric MinPower floor stored by the
90	// no-changes smart-retry path, which advances one ladder step at a time.
91	// Tier-name string hints (from the review-triage path) are not matched here.
92	func numericTierFloorHint(b *bead.Bead) (int, bool) {
93		if b == nil || b.Extra == nil {
94			return 0, false
95		}
96		raw, ok := b.Extra[agent.TriageTierHintKey]
97		if !ok {
98			return 0, false
99		}
100		switch v := raw.(type) {
101		case int:
102			return v, v > 0
103		case int64:
104			return int(v), int(v) > 0
105		case float64:
106			return int(v), int(v) > 0
107		default:
108			return 0, false
109		}
110	}
111	
112	func triageTierHint(b *bead.Bead) (policyescalation.ModelTier, bool) {
113		if b == nil || b.Extra == nil {
114			return "", false
115		}
116		raw, ok := b.Extra[agent.TriageTierHintKey]
117		if !ok {
118			return "", false
119		}
120		switch strings.ToLower(strings.TrimSpace(fmt.Sprint(raw))) {
121		case string(policyescalation.TierSmart):
122			return policyescalation.TierSmart, true
123		case string(policyescalation.TierStandard):
124			return policyescalation.TierStandard, true
125		case string(policyescalation.TierCheap):
126			return policyescalation.TierCheap, true
127		default:
128			return "", false
129		}
130	}
