315	func buildDecompositionParkingEvent(report Report) *ParkingEvent {
316		body, mErr := json.Marshal(map[string]any{
317			"rationale":            report.DecompositionRationale,
318			"recommended_subbeads": report.DecompositionRecommendation,
319			"detail":               report.Detail,
320			"base_rev":             report.BaseRev,
321			"session_id":           report.SessionID,
322		})
323		bodyStr := ""
324		if mErr == nil {
325			bodyStr = string(body)
326		} else {
327			bodyStr = fmt.Sprintf("rationale=%s\nrecommended_subbeads=%v",
328				report.DecompositionRationale, report.DecompositionRecommendation)
329		}
330		summary := "agent declined: needs decomposition"
331		if n := len(report.DecompositionRecommendation); n > 0 {
332			summary = fmt.Sprintf("%s (%d sub-beads)", summary, n)
333		}
334		return &ParkingEvent{
335			Kind:    "decomposition-recommendation",
336			Summary: summary,
337			Body:    bodyStr,
338		}
339	}
