399	func resolveRateLimitRetryConfig(opts AttemptOpts) RateLimitRetryConfig {
400		cfg := RateLimitRetryConfig{
401			Budget:     opts.RateLimitBudget,
402			PerWaitCap: opts.RateLimitPerWaitCap,
403			Evaluator:  opts.RateLimitWaitEvaluator,
404			Sleep:      opts.RateLimitSleep,
405			Now:        opts.RateLimitNow,
406			OnRetry:    opts.RateLimitOnRetry,
407		}
408		if cfg.Budget == 0 {
409			cfg.Budget = RateLimitRetryDefaultBudget
410		}
411		if cfg.PerWaitCap == 0 {
412			cfg.PerWaitCap = RateLimitRetryDefaultPerWaitCap
413		}
414		if cfg.Sleep == nil {
415			cfg.Sleep = ctxSleep
416		}
417		if cfg.Now == nil {
418			cfg.Now = time.Now
419		}
420		if cfg.Evaluator == nil {
421			cfg.Evaluator = EvaluateRateLimitWait
422		}
423		return cfg
424	}
