440	func evaluateRateLimitAttempt(report Report, cfg RateLimitRetryConfig, attempt int, elapsed, budget time.Duration) (RateLimitWaitDecision, time.Duration) {
441		if cfg.Budget < 0 || budget < 0 {
442			return RateLimitWaitDecision{ShouldRetry: false}, 0
443		}
444		if !IsRateLimitReport(&report) {
445			return RateLimitWaitDecision{ShouldRetry: false}, 0
446		}
447	
448		retryAfter := ExtractRetryAfterFromStderr(report.Stderr, cfg.Now())
449		decision := cfg.Evaluator(retryAfter, attempt, elapsed, budget, cfg.PerWaitCap)
450		if !decision.ShouldRetry {
451			decision.Reason = RateLimitBudgetExhaustedReason
452		}
453		return decision, retryAfter
454	}
455	
456	func EvaluateRateLimitWait(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision {
457		if budget > 0 && elapsed >= budget {
458			return RateLimitWaitDecision{ShouldRetry: false, Reason: RateLimitBudgetExhaustedReason}
459		}
460	
461		var wait time.Duration
462		var source string
463		if retryAfter > 0 {
464			wait = retryAfter
465			source = "retry-after"
466		} else {
467			idx := attempt - 1
468			if idx < 0 {
469				idx = 0
470			}
471			if idx >= len(rateLimitBackoffSchedule) {
472				idx = len(rateLimitBackoffSchedule) - 1
473			}
474			wait = rateLimitBackoffSchedule[idx]
475			source = "exponential-backoff"
476		}
477	
478		if perWaitCap > 0 && wait > perWaitCap {
479			wait = perWaitCap
480		}
481	
482		if budget > 0 && elapsed+wait > budget {
483			remaining := budget - elapsed
484			if remaining <= 0 {
485				return RateLimitWaitDecision{ShouldRetry: false, Reason: RateLimitBudgetExhaustedReason}
486			}
487			wait = remaining
488		}
489	
490		return RateLimitWaitDecision{ShouldRetry: true, Wait: wait, Source: source}
491	}
