493	func IsRateLimitReport(report *Report) bool {
494		if report == nil {
495			return false
496		}
497		combined := strings.ToLower(report.Error + "\n" + report.Stderr + "\n" + report.Detail)
498		if combined == "\n\n" {
499			return false
500		}
501		if strings.Contains(combined, "quota exceeded") ||
502			strings.Contains(combined, "insufficient quota") ||
503			strings.Contains(combined, "no viable provider") {
504			return false
505		}
506		if strings.Contains(combined, "rate limit") || strings.Contains(combined, "ratelimit") {
507			return true
508		}
509		return hasIsolated429(combined)
510	}
511	
512	func hasIsolated429(s string) bool {
513		for i := 0; i+3 <= len(s); i++ {
514			if s[i:i+3] != "429" {
515				continue
516			}
517			if i > 0 {
518				c := s[i-1]
519				if c >= '0' && c <= '9' {
520					continue
521				}
522			}
523			if i+3 < len(s) {
524				c := s[i+3]
525				if c >= '0' && c <= '9' {
526					continue
527				}
528			}
529			return true
530		}
531		return false
532	}
