	}
	if repaired.CycleIndex <= previous.CycleIndex {
		repaired.CycleIndex = previous.CycleIndex + 1
	}
	if repaired.Report.BeadID == "" {
		repaired.Report.BeadID = previous.Report.BeadID
	}
	if repaired.Report.AttemptID == "" {
		repaired.Report.AttemptID = previous.Report.AttemptID
	}
	if repaired.Report.BaseRev == "" {
		repaired.Report.BaseRev = previous.Report.BaseRev
	}
	if repaired.Report.Status == "" {
		repaired.Report.Status = ExecuteBeadStatusSuccess
	}
	if repaired.Report.CycleIndex == 0 && repaired.CycleIndex != 0 {
		repaired.Report.CycleIndex = repaired.CycleIndex
	}
	// Propagate ActualPower so EscalationNextFloor can compute the correct next
	// floor after repair cycles exhaust on the repaired candidate.
	if repaired.Report.ActualPower == 0 && previous.Report.ActualPower > 0 {
		repaired.Report.ActualPower = previous.Report.ActualPower
	}
	repaired.Report.CandidateRef = ""
	repaired.Report.ReviewVerdict = ""
	repaired.Report.ReviewRationale = ""
	return repaired
}

// isTerminalCandidateReviewClass reports whether a review classification class
// is a terminal operator-required condition that must not enter the automated
// repair or escalation cycle.
func isTerminalCandidateReviewClass(class string) bool {
	switch class {
	case ReviewTerminalClassSpecGap, ReviewTerminalClassMissingAcceptance,
		ReviewTerminalClassTooLarge, ReviewTerminalClassUnsafeOrOutScope:
		return true
	}
	return false
}

