// TestReviewBlock_EscalatesImplementerOnRepairExhaustion asserts that when repair
// cycles exhaust on a fixable BLOCK and the ladder has a next tier, the coordinator
// returns an escalatable status so the outer loop retries at higher MinPower (ADR-024 P2).
func TestReviewBlock_EscalatesImplementerOnRepairExhaustion(t *testing.T) {
	var landerCalled bool
	coord := &AttemptCycleCoordinator{
		Pass: implementationPassFunc(func(_ context.Context, beadID string) (CandidateResult, error) {
			return CandidateResult{
				Report: ExecuteBeadReport{
					BeadID:      beadID,
					AttemptID:   "attempt-escalate-001",
					Status:      ExecuteBeadStatusSuccess,
					BaseRev:     "base-rev",
					ResultRev:   "candidate-rev",
					ActualPower: 10,
				},
				WorktreePath: "/attempt/worktree",
			}, nil
		}),
		Reviewer: candidateReviewerFunc(func(_ context.Context, _ string, _ CandidateResult) (CandidateReviewResult, error) {
			return escalationFixableBlockReview(), nil
		}),
		Repair: repairPassFunc(func(_ context.Context, candidate CandidateResult, _ string) (CandidateResult, error) {
			return repairCycleCandidate(candidate.Report.BeadID, candidate.Report.AttemptID, candidate.Report.BaseRev, "repaired-rev", candidate.CycleIndex+1), nil
		}),
		Lander: candidateLanderFunc(func(_ context.Context, c CandidateResult) (ExecuteBeadReport, error) {
			landerCalled = true
			t.Fatalf("lander must not run after repair budget exhaustion: %+v", c)
			return c.Report, nil
		}),
		RepairMaxCycles: 1,
		EscalationNextFloor: func(actualPower int) (int, error) {
			return actualPower + 10, nil // next tier is available
		},
	}

	result, err := coord.Run(context.Background(), "ddx-escalate-bead")
	require.NoError(t, err)
	assert.False(t, landerCalled)
	assert.False(t, result.Landed)
	// Status must be escalatable so the outer loop bumps MinPower for the next attempt.
	assert.True(t, escalation.ShouldEscalate(result.Report.Status),
		"got non-escalatable status %q after repair exhaustion with valid next tier", result.Report.Status)
}

// TestReviewBlock_StillFailsAtTopTier_ParkProposed asserts that when repair cycles
// exhaust at the top ladder tier (ErrLadderExhausted), the coordinator parks as
// repair-cycle-exhausted rather than escalating forever.
func TestReviewBlock_StillFailsAtTopTier_ParkProposed(t *testing.T) {
	coord := &AttemptCycleCoordinator{
		Pass: implementationPassFunc(func(_ context.Context, beadID string) (CandidateResult, error) {
			return repairCycleCandidate(beadID, "attempt-top-tier", "base-rev", "candidate-rev", 0), nil
		}),
		Reviewer: candidateReviewerFunc(func(_ context.Context, _ string, _ CandidateResult) (CandidateReviewResult, error) {
			return escalationFixableBlockReview(), nil
		}),
		Repair: repairPassFunc(func(_ context.Context, candidate CandidateResult, _ string) (CandidateResult, error) {
			return repairCycleCandidate(candidate.Report.BeadID, candidate.Report.AttemptID, candidate.Report.BaseRev, "repaired-rev", 1), nil
		}),
		Lander: candidateLanderFunc(func(_ context.Context, c CandidateResult) (ExecuteBeadReport, error) {
			t.Fatalf("lander must not run: %+v", c)
			return c.Report, nil
		}),
		RepairMaxCycles: 1,
		EscalationNextFloor: func(actualPower int) (int, error) {
			return 0, errors.New("ladder exhausted") // already at top tier
		},
	}

	result, err := coord.Run(context.Background(), "ddx-top-tier-bead")
	require.NoError(t, err)
	assert.False(t, result.Landed)
	assert.Equal(t, ExecuteBeadStatusRepairCycleExhausted, result.Report.Status,
		"top-tier repair exhaustion must park as repair-cycle-exhausted")
	assert.False(t, escalation.ShouldEscalate(result.Report.Status),
		"repair-cycle-exhausted must not be escalatable (would cause an infinite loop)")
}

// TestReviewBlock_NonFixableClassification_DoesNotEscalate asserts that spec_gap and
// too_large BLOCK verdicts park directly as review_terminal_block and never enter the
// repair or escalation cycle (those require operator reframe/decompose, not a bigger model).
func TestReviewBlock_NonFixableClassification_DoesNotEscalate(t *testing.T) {
	tests := []struct {
		name    string
		finding Finding
	}{
		{
			name:    "spec_gap",
			finding: Finding{Severity: "block", Summary: "spec gap - requirements unclear", Location: "bead:AC1"},
		},
		{
			name:    "too_large",
			finding: Finding{Severity: "block", Summary: "too large - needs decomposition", Location: "bead:AC1"},
		},
	}
	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			var repairCalled bool
			coord := &AttemptCycleCoordinator{
				Pass: implementationPassFunc(func(_ context.Context, beadID string) (CandidateResult, error) {
					return repairCycleCandidate(beadID, "attempt-nonfixable", "base-rev", "candidate-rev", 0), nil
				}),
				Reviewer: candidateReviewerFunc(func(_ context.Context, _ string, _ CandidateResult) (CandidateReviewResult, error) {
					return CandidateReviewResult{
						Verdict:   "BLOCK",
						Rationale: tc.finding.Summary,
						Findings:  []Finding{tc.finding},
					}, nil
				}),
				Repair: repairPassFunc(func(_ context.Context, candidate CandidateResult, _ string) (CandidateResult, error) {
					repairCalled = true
					return repairCycleCandidate(candidate.Report.BeadID, candidate.Report.AttemptID, candidate.Report.BaseRev, "repaired-rev", 1), nil
				}),
				Lander: candidateLanderFunc(func(_ context.Context, c CandidateResult) (ExecuteBeadReport, error) {
					t.Fatalf("lander must not run: %+v", c)
					return c.Report, nil
				}),
				EscalationNextFloor: func(actualPower int) (int, error) {
					return actualPower + 10, nil // would escalate if reachable
				},
			}

			result, err := coord.Run(context.Background(), "ddx-nonfixable-bead")
			require.NoError(t, err)
			assert.False(t, result.Landed)
			assert.False(t, repairCalled, "repair must not run for non-fixable %s classification", tc.name)
			assert.Equal(t, ExecuteBeadStatusReviewTerminalBlock, result.Report.Status,
				"non-fixable %s block must park as review_terminal_block", tc.name)
			assert.False(t, escalation.ShouldEscalate(result.Report.Status),
				"review_terminal_block must not be escalatable")
		})
	}
}

